import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { TerroristsFile } from "src/app/views/Models/Terrorism/terrorists.model";
import { EnvService } from "../env.service";

@Injectable({
  providedIn: "root",
})
export class FilesService {
  constructor(private env: EnvService, private http: HttpClient) {}

  async uploadData(terroristsFile: TerroristsFile): Promise<boolean> {
    try {
      var response = this.http
        .post<any>(
          `${this.env.API_URL}api/Terrorism/UploadTerrorismFile`,
          terroristsFile
        )
        .toPromise();
      return response;
    } catch (e) {
      console.log(e);
    }

    console.log(response);
  }
}
