import { Injectable } from '@angular/core';
import * as XLSX from 'xlsx';
import { BehaviorSubject } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class FileConverterService {
  private terroristsData = new BehaviorSubject<string[][] | undefined>(
    undefined
  );
  public terroristsData$ = this.terroristsData.asObservable();

  constructor() {}

  structureData(fileReceived: DataTransfer) {
    const reader: FileReader = new FileReader();
    let terroristsData: string[][] = [];
    reader.onload = (e: any) => {
      const binarystring: string = e.target.result;
      console.log(binarystring);

      const workbook: XLSX.WorkBook = XLSX.read(binarystring, {
        type: 'binary',
      });
      const worksheetname = workbook.SheetNames[0];
      console.log(workbook.Sheets);
      const worksheet: XLSX.WorkSheet = workbook.Sheets[worksheetname];

      // Converting to JSON
      let sheetData = XLSX.utils.sheet_to_json<string[]>(worksheet, {
        header: 1,
      });

      let data = sheetData.map<string[]>((items) => {
        return items.map<string>((item) => {
          return item.toString();
        });
      });
      console.log(sheetData, 'data');
      this.terroristsData.next(data);
    };

    reader.readAsArrayBuffer(fileReceived.files[0]);
  }
}
