import { Component } from "@angular/core";
import { CommonModule } from "@angular/common";
import * as XLSX from "xlsx";
import { pagingService } from "src/app/core/services/paging.service";
import { TerroristsFile } from "src/app/views/Models/Terrorism/terrorists.model";
import { FileConverterService } from "src/app/core/services/files/file-converter/file-converter.service";
import { FilesService } from "src/app/core/services/files/files.service";
import { AlertService } from "src/app/core/services/alert.service";

@Component({
  selector: "app-upload",
  templateUrl: "./upload.page.html",
  styleUrls: ["./upload.page.scss"],
})
export class UploadComponent {
  showLoader: boolean = false;
  terroristsHeaderData?: string[];
  terroristsData?: string[][];
  terroristsFileName?: string;
  pagedTerroristsData?: string[][];

  pageSize: number = 10;
  pageNo: number = 1;

  constructor(
    private fileConverter: FileConverterService,
    private files: FilesService,
    private paging: pagingService,
    private alertService: AlertService
  ) {}

  onFileSubmit(evt: any) {
    // File received
    const fileReceived: DataTransfer = <DataTransfer>evt.target;
    // Check how many files are received
    if (fileReceived.files.length > 1) {
      return;
    } else {
      this.terroristsFileName = fileReceived.files[0].name;
      this.fileConverter.terroristsData$.subscribe((terroristsData) => {
        this.terroristsData = terroristsData;
        if (this.terroristsData) {
          this.terroristsHeaderData = this.terroristsData.splice(0, 1)[0];
          this.pageNo = 1;
          this.pagedTerroristsData = this.paging.Paging(
            this.terroristsData,
            this.pageNo
          );
          console.log(this.pagedTerroristsData);
        }
      });
      this.fileConverter.structureData(fileReceived);
    }
  }

  onPageChanged(pageNo: number) {
    if (this.terroristsData) {
      this.pageNo = pageNo;
      this.pagedTerroristsData = this.paging.Paging(
        this.terroristsData,
        pageNo
      );
    }
  }

  async uploadFile() {
    if (this.terroristsData && this.terroristsFileName) {
      this.showLoader = true;
      let file: TerroristsFile = {
        fileName: this.terroristsFileName,
        terrorists: this.terroristsData,
      };
      let result = await this.files.uploadData(file);
      if (result) {
        await this.alertService.showAlertConfirm("لقد تم الحفظ بنجاح", false);
      } else {
        await this.alertService.showAlertError(`حدث خطأ فى حفظ الملف`, false);
      }
      this.showLoader = false;
    }
  }
}
